import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Two-Factor Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"app/two-factor.md","filePath":"app/two-factor.md"}'),n={name:"app/two-factor.md"};function s(i,e,c,l,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="two-factor-authentication" tabindex="-1">Two-Factor Authentication <a class="header-anchor" href="#two-factor-authentication" aria-label="Permalink to &quot;Two-Factor Authentication&quot;">​</a></h1><p>Two-factor authentication (2FA) adds a second step to every sign-in: after your password, you enter a time-based one-time code (TOTP) from an authenticator app. You manage it from the <strong>Security</strong> section of your <a href="/app/account">Account settings</a>.</p><div class="info custom-block"><p class="custom-block-title">Server requirement</p><p>The server must have the <code>TWO_FACTOR_KEY</code> environment variable set to a base64-encoded 32-byte value. It is used to encrypt stored TOTP secrets at rest. Without it, enrolment fails. See <a href="/self-hosting/requirements">self-hosting requirements</a>.</p></div><h2 id="enable-two-factor" tabindex="-1">Enable two-factor <a class="header-anchor" href="#enable-two-factor" aria-label="Permalink to &quot;Enable two-factor&quot;">​</a></h2><ol><li>Open <strong>Account settings</strong> and find the <strong>Two-factor authentication</strong> card. If it shows the <strong>Inactive</strong> badge, click <strong>Set up two-factor</strong>.</li><li>Scan the displayed <strong>QR code</strong> with a TOTP app such as 1Password, Authy or Google Authenticator. If you cannot scan, enter the shown secret manually.</li><li>Enter the <strong>6-digit code</strong> from your app and click <strong>Enable</strong>.</li><li>Tragwerk then shows your <strong>recovery codes</strong> — save them before continuing (see below).</li></ol><p>Once enabled, the card shows an <strong>Active</strong> badge and the date 2FA was set up.</p><h2 id="recovery-codes" tabindex="-1">Recovery codes <a class="header-anchor" href="#recovery-codes" aria-label="Permalink to &quot;Recovery codes&quot;">​</a></h2><p>Recovery codes are one-time codes that let you sign in when you cannot reach your authenticator app (for example, a lost phone).</p><ul><li>They are shown <strong>only once</strong>, right after you enable 2FA. Store them somewhere safe.</li><li><strong>Each code can be used once.</strong> The account card shows how many unused codes remain.</li><li>To replace them, open the card and use <strong>Manage codes</strong> to generate a fresh set. Generating new codes invalidates the previous ones.</li></ul><div class="warning custom-block"><p class="custom-block-title">Save them immediately</p><p>You will not be able to view existing codes again. If you lose both your authenticator app and your recovery codes, you will be locked out and need an administrator to intervene on the server.</p></div><h2 id="the-login-challenge" tabindex="-1">The login challenge <a class="header-anchor" href="#the-login-challenge" aria-label="Permalink to &quot;The login challenge&quot;">​</a></h2><p>When 2FA is active, signing in becomes a two-step flow:</p><ol><li>Enter your email and password as usual.</li><li>On the <strong>Two-factor authentication</strong> screen, enter the <strong>6-digit code</strong> from your app — or choose <strong>Use a recovery code instead</strong> and enter one of your recovery codes.</li><li>Optionally tick <strong>Don&#39;t ask again on this device</strong> to mark the current device as trusted for a number of days and skip the challenge during that window.</li></ol><h2 id="disable-two-factor" tabindex="-1">Disable two-factor <a class="header-anchor" href="#disable-two-factor" aria-label="Permalink to &quot;Disable two-factor&quot;">​</a></h2><ol><li>In the <strong>Two-factor authentication</strong> card, click <strong>Disable two-factor</strong>.</li><li>Confirm with your <strong>current password</strong> in the dialog.</li></ol><p>After disabling, your account is protected by password only — re-enable 2FA to restore the second factor.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/account">Account</a></li><li><a href="/self-hosting/requirements">Self-hosting requirements</a></li></ul>',18)])])}const p=t(n,[["render",s]]);export{g as __pageData,p as default};
